"""
This module manages the game board and its state.
"""

class Piece:
    def __init__(self, color):
        self.color = color  # 'w' for white, 'b' for black
        self.king = False

    def king_piece(self):
        self.king = True


class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Initialize the board with pieces
        colors = ['w', 'b']
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece(colors[i % 2])
        for i in range(5, 8):
            for j in range(1, 9, 2):
                self.board[i][j] = Piece(colors[(i - 3) % 2])

    def print_board(self):
        from termcolor import colored

        colors = {'w': 'white', 'b': 'blue'}
        for row in self.board:
            line = []
            for piece in row:
                if piece is None:
                    line.append(' . ')
                elif piece.king:
                    line.append(colored(f'K{piece.color[0]}', colors[piece.color]))
                else:
                    line.append(colored(piece.color[0], colors[piece.color]))
            print(' '.join(line))

    def move_piece(self, start, end):
        x1, y1 = start
        x2, y2 = end
        if self.board[x1][y1] is not None and abs(x1 - x2) == 2 and abs(y1 - y2) == 2:
            # Capture move
            mid_x, mid_y = (x1 + x2) // 2, (y1 + y2) // 2
            self.board[mid_x][mid_y] = None
        self.board[x2][y2], self.board[x1][y1] = self.board[x1][y1], None

    def is_valid_move(self, start, end):
        x1, y1 = start
        x2, y2 = end
        piece = self.board[x1][y1]
        if piece is None:
            return False
        dx, dy = abs(x1 - x2), abs(y1 - y2)
        if dx != 1 or dy != 1 and (dx != 2 or dy != 2):
            return False
        if dx == 2 and dy == 2:  # Capture move
            mid_x, mid_y = (x1 + x2) // 2, (y1 + y2) // 2
            if self.board[mid_x][mid_y] is None or self.board[mid_x][mid_y].color == piece.color:
                return False
        if piece.king or (piece.color == 'w' and x2 < x1) or (piece.color == 'b' and x2 > x1):
            return True
        return False

    def has_valid_moves(self, color):
        for i in range(8):
            for j in range(8):
                if self.board[i][j] is not None and self.board[i][j].color == color:
                    if any(self.is_valid_move((i, j), (i + dx, j + dy)) for dx in [-1, 1] for dy in [-1, 1]):
                        return True
        return False
```

