"""
This module manages the game flow.
"""

from board import Board, Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'w'
        self.game_over = False

    def print_board(self):
        self.board.print_board()

    def take_turn(self):
        if self.current_player == 'w':
            player = "White"
        else:
            player = "Black"

        start_pos = input(f"{player}, enter your move (e.g., 1A 3C): ").upper().split()
        if len(start_pos) != 2:
            print("Invalid move format. Please use from-to positions.")
            return

        start = self.convert_to_coords(start_pos[0])
        end = self.convert_to_coords(start_pos[1])

        if not start or not end:
            print("Invalid coordinate. Please enter valid positions (A-H, 1-8).")
            return

        if not self.board.is_valid_move(start, end):
            print("Invalid move. Please make a valid move.")
            return

        self.board.move_piece(start, end)

        if self.current_player == 'w':
            self.current_player = 'b'
        else:
            self.current_player = 'w'

    def convert_to_coords(self, pos):
        if len(pos) != 2 or not pos[0].isalpha() or not pos[1].isdigit():
            return None
        col = ord(pos[0]) - ord('A')
        row = int(pos[1]) - 1
        if col < 0 or col > 7 or row < 0 or row > 7:
            return None
        return (row, col)

    def check_game_over(self):
        if not self.board.has_valid_moves(self.current_player):
            self.game_over = True
            print("Game Over!")
            winner = 'White' if self.current_player == 'b' else 'Black'
            print(f"{winner} wins!")

if __name__ == "__main__":
    game = Game()
    while not game.game_over:
        game.print_board()
        game.take_turn()
        game.check_game_over()
